package com.izonehub.stores.user;import com.izonehub.stores.auth.PasswordPolicy;import com.izonehub.stores.store.Store;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class UserCommandService{private final UserRepository repo;private final PasswordEncoder encoder;private final PasswordPolicy policy;public UserCommandService(UserRepository repo,PasswordEncoder encoder,PasswordPolicy policy){this.repo=repo;this.encoder=encoder;this.policy=policy;} @Transactional public AppUser createUser(String fullName,String email,String temporaryPassword,Role role,Store assignedStore,AppUser createdBy){if(role==Role.SYSTEM_ADMINISTRATOR)throw new IllegalArgumentException("System Administrator accounts cannot be created through application user management"); if(!policy.isValid(temporaryPassword))throw new IllegalArgumentException("Password does not meet policy"); if(repo.existsByEmail(email.toLowerCase()))throw new IllegalArgumentException("Email already exists"); return repo.save(new AppUser(fullName,email,encoder.encode(temporaryPassword),role,assignedStore,createdBy));}}
